// 先建立可见状态,再载入并用 JS 创建已注册的 custom element
const host = document.getElementById('board'); host.style.minHeight = '480px'; host.textContent = 'Loading chessboard…';
await import('https://cdn.jsdelivr.net/npm/chessboard-element@1/+esm');
const b = document.createElement('chess-board'); // 铁律 4:custom element 必须 JS 创建
b.style.cssText = 'display:block;width:480px;max-width:100%;height:480px';
b.orientation = data.orientation ?? 'white'; b.draggablePieces = data.draggable ?? false; b.setPosition(data.fen, false);
host.textContent = ''; host.appendChild(b);

